mapper.select:
SELECT CASE
           WHEN t.subject_code IS NOT NULL AND TRIM(t.subject_code) != '' THEN t.subject_code
           WHEN t.transaction_type = #{incomeType} THEN #{unclassifiedIncomeCode}
           WHEN t.transaction_type = #{expenseType} THEN #{unclassifiedExpenseCode}
           ELSE NULL
           END AS subjectCode,
       COALESCE(SUM(CASE WHEN t.transaction_type = #{incomeType} THEN t.amount ELSE 0 END), 0) AS incomeAmount,
       COALESCE(SUM(CASE WHEN t.transaction_type = #{expenseType} THEN t.amount ELSE 0 END), 0) AS expenseAmount
FROM finance_transaction t
WHERE t.deleted = 0
  AND t.company_id = #{companyId}
  AND t.status = #{successStatus}
  AND (t.transaction_type = #{incomeType} OR t.transaction_type = #{expenseType})
  AND t.transaction_period >= #{startPeriod}
  AND t.transaction_period <= #{endPeriod}
GROUP BY CASE
             WHEN t.subject_code IS NOT NULL AND TRIM(t.subject_code) != '' THEN t.subject_code
             WHEN t.transaction_type = #{incomeType} THEN #{unclassifiedIncomeCode}
             WHEN t.transaction_type = #{expenseType} THEN #{unclassifiedExpenseCode}
             ELSE NULL
    END

SELECT COALESCE(SUM(CASE WHEN t.transaction_type = #{incomeType} THEN t.amount ELSE 0 END), 0) AS incomeAmount,
       COALESCE(SUM(CASE WHEN t.transaction_type = #{expenseType} THEN t.amount ELSE 0 END), 0) AS expenseAmount
FROM finance_transaction t
WHERE t.deleted = 0
  AND t.company_id = #{companyId}
  AND t.status = #{successStatus}
  AND (t.transaction_type = #{incomeType} OR t.transaction_type = #{expenseType})
  AND t.transaction_period = #{period}

SELECT DATE_FORMAT(
           DATE_SUB(DATE(t.transaction_date), INTERVAL WEEKDAY(DATE(t.transaction_date)) DAY),
           '%Y-%m-%d'
       ) AS weekStartDate,
       COALESCE(SUM(CASE WHEN t.transaction_type = #{incomeType} THEN t.amount ELSE 0 END), 0) AS incomeAmount,
       COALESCE(SUM(CASE WHEN t.transaction_type = #{expenseType} THEN t.amount ELSE 0 END), 0) AS expenseAmount
FROM finance_transaction t
WHERE t.deleted = 0
  AND t.company_id = #{companyId}
  AND t.status = #{successStatus}
  AND (t.transaction_type = #{incomeType} OR t.transaction_type = #{expenseType})
  AND t.transaction_date >= #{startTime}
  AND t.transaction_date < #{endTime}
GROUP BY DATE_FORMAT(
             DATE_SUB(DATE(t.transaction_date), INTERVAL WEEKDAY(DATE(t.transaction_date)) DAY),
             '%Y-%m-%d'
         )
ORDER BY weekStartDate ASC
